@@ -1,0 +1,86 @@
+const DB_NAME = 'SiteInspectorDb';
+const DB_VERSION = 1;
+
+let db = null;
+
+export function initDb() {
+    return new Promise((resolve, reject) => {
+        if (db) { resolve(); return; }
+        const request = indexedDB.open(DB_NAME, DB_VERSION);
+        request.onupgradeneeded = (event) => {
+            const database = event.target.result;
+            if (!database.objectStoreNames.contains('sites')) {
+                database.createObjectStore('sites', { keyPath: 'id' });
+            }
+            if (!database.objectStoreNames.contains('inspections')) {
+                const store = database.createObjectStore('inspections', { keyPath: 'id' });
+                store.createIndex('siteId', 'siteId', { unique: false });
+                store.createIndex('isSynced', 'isSynced', { unique: false });
+            }
+        };
+        request.onsuccess = (event) => {
+            db = event.target.result;
+            resolve();
+        };
+        request.onerror = (event) => reject(event.target.error);
+    });
+}
+
+export function putItem(storeName, jsonString) {
+    return new Promise((resolve, reject) => {
+        const item = JSON.parse(jsonString);
+        const tx = db.transaction(storeName, 'readwrite');
+        const store = tx.objectStore(storeName);
+        const request = store.put(item);
+        request.onsuccess = () => resolve();
+        request.onerror = (event) => reject(event.target.error);
+    });
+}
+
+export function getItem(storeName, id) {
+    return new Promise((resolve, reject) => {
+        const tx = db.transaction(storeName, 'readonly');
+        const store = tx.objectStore(storeName);
+        const request = store.get(id);
+        request.onsuccess = () => {
+            resolve(request.result ? JSON.stringify(request.result) : null);
+        };
+        request.onerror = (event) => reject(event.target.error);
+    });
+}
+
+export function getAllItems(storeName) {
+    return new Promise((resolve, reject) => {
+        const tx = db.transaction(storeName, 'readonly');
+        const store = tx.objectStore(storeName);
+        const request = store.getAll();
+        request.onsuccess = () => resolve(JSON.stringify(request.result || []));
+        request.onerror = (event) => reject(event.target.error);
+    });
+}
+
+export function deleteItem(storeName, id) {
+    return new Promise((resolve, reject) => {
+        const tx = db.transaction(storeName, 'readwrite');
+        const store = tx.objectStore(storeName);
+        const request = store.delete(id);
+        request.onsuccess = () => resolve();
+        request.onerror = (event) => reject(event.target.error);
+    });
+}
+
+export function getItemsByIndex(storeName, indexName, value) {
+    return new Promise((resolve, reject) => {
+        const tx = db.transaction(storeName, 'readonly');
+        const store = tx.objectStore(storeName);
+        const index = store.index(indexName);
+        // Convert string 'false'/'true' to boolean for isSynced index
+        let queryValue = value;
+        if (value === 'true') queryValue = true;
+        else if (value === 'false') queryValue = false;
+        const request = index.getAll(queryValue);
+        request.onsuccess = () => resolve(JSON.stringify(request.result || []));
+        request.onerror = (event) => reject(event.target.error);
+    });
+}
+

