+using System.Net.Http.Json;
+using SiteInspector.Client.Models;
+
+namespace SiteInspector.Client.Services;
+
+public class SyncService : IAsyncDisposable
+{
+    private readonly InspectionService _inspectionService;
+    private readonly HttpClient _http;
+    private readonly ILogger<SyncService> _logger;
+    private Timer? _timer;
+
+    public bool IsOnline { get; private set; } = true;
+    public event Action? OnConnectivityChanged;
+    public DateTime? LastSyncedAt { get; private set; }
+
+    public SyncService(InspectionService inspectionService, HttpClient http, ILogger<SyncService> logger)
+    {
+        _inspectionService = inspectionService;
+        _http = http;
+        _logger = logger;
+    }
+
+    public void Start()
+    {
+        _timer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
+    }
+
+    public async Task TrySyncAsync()
+    {
+        try
+        {
+            var response = await _http.GetAsync("api/sync/ping");
+            var wasOffline = !IsOnline;
+            IsOnline = response.IsSuccessStatusCode;
+
+            if (wasOffline && IsOnline)
+                OnConnectivityChanged?.Invoke();
+
+            if (!IsOnline) return;
+
+            // Upload unsynced inspections
+            var unsynced = await _inspectionService.GetUnsyncedInspectionsAsync();
+            foreach (var inspection in unsynced)
+            {
+                try
+                {
+                    var syncResponse = await _http.PostAsJsonAsync("api/sync/inspections", inspection);
+                    if (syncResponse.IsSuccessStatusCode)
+                    {
+                        inspection.IsSynced = true;
+                        await _inspectionService.SaveInspectionAsync(inspection);
+                    }
+                }
+                catch { /* individual failure, try next */ }
+            }
+
+            // Upload sites
+            var sites = await _inspectionService.GetSitesAsync();
+            foreach (var site in sites)
+            {
+                try { await _http.PostAsJsonAsync("api/sync/sites", site); }
+                catch { /* best effort */ }
+            }
+
+            LastSyncedAt = DateTime.UtcNow;
+            OnConnectivityChanged?.Invoke();
+        }
+        catch
+        {
+            if (IsOnline) { IsOnline = false; OnConnectivityChanged?.Invoke(); }
+        }
+    }
+
+    public ValueTask DisposeAsync()
+    {
+        _timer?.Dispose();
+        return ValueTask.CompletedTask;
+    }
+}
+

