@page "/"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject InspectionService InspectionSvc
@inject SyncService SyncSvc

<PageTitle>Site Inspector</PageTitle>

<div class="dashboard">
    <header class="dashboard-header">
        <h1>🏗️ Site Inspector</h1>
        <div class="connectivity-badge @(SyncSvc.IsOnline ? "online" : "offline")">
            @(SyncSvc.IsOnline ? "● Online" : "● Offline")
        </div>
    </header>

    @if (_loading)
    {
        <div class="loading">Loading...</div>
    }
    else
    {
        <section class="quick-actions">
            <a href="/sites" class="action-card">
                <span class="action-icon">🏢</span>
                <span class="action-label">Manage Sites</span>
                <span class="action-count">@_sites.Count sites</span>
            </a>
            <a href="/sites" class="action-card primary">
                <span class="action-icon">📋</span>
                <span class="action-label">New Inspection</span>
                <span class="action-count">Select a site</span>
            </a>
        </section>

        <section class="recent-section">
            <h2>Recent Inspections</h2>
            @if (_inspections.Count == 0)
            {
                <div class="empty-state">
                    <p>No inspections yet. Add a site and start your first inspection.</p>
                </div>
            }
            else
            {
                <div class="inspection-list">
                    @foreach (var inspection in _inspections.OrderByDescending(i => i.InspectedAt).Take(10))
                    {
                        <a href="/inspection/@inspection.Id" class="inspection-card">
                            <div class="inspection-card-header">
                                <span class="site-name">@inspection.SiteName</span>
                                <span class="status-badge @inspection.Status.ToString().ToLower()">
                                    @inspection.Status
                                </span>
                            </div>
                            <div class="inspection-card-body">
                                <span>@inspection.InspectorName</span>
                                <span>@inspection.InspectedAt.ToLocalTime().ToString("MMM dd, HH:mm")</span>
                            </div>
                            <div class="inspection-card-footer">
                                <span class="sync-status">@(inspection.IsSynced ? "✓ Synced" : "⏳ Pending sync")</span>
                                <span>@inspection.ChecklistItems.Count(i => i.Result != CheckResult.NotChecked)/@inspection.ChecklistItems.Count items</span>
                            </div>
                        </a>
                    }
                </div>
            }
        </section>

        @if (SyncSvc.LastSyncedAt.HasValue)
        {
            <div class="last-sync">
                Last synced: @SyncSvc.LastSyncedAt.Value.ToLocalTime().ToString("HH:mm:ss")
            </div>
        }
    }
</div>

@code {
    private List<ConstructionSite> _sites = new();
    private List<Inspection> _inspections = new();
    private bool _loading = true;

    protected override async Task OnInitializedAsync()
    {
        SyncSvc.OnConnectivityChanged += StateHasChanged;
        await InspectionSvc.EnsureInitializedAsync();
        _sites = await InspectionSvc.GetSitesAsync();
        _inspections = await InspectionSvc.GetAllInspectionsAsync();
        _loading = false;
        SyncSvc.Start();
    }
}

