    private List<ConstructionSite> _sites = new();
    private string _newName = "";
    private string _newAddress = "";

    protected override async Task OnInitializedAsync()
    {
        await InspectionSvc.EnsureInitializedAsync();
        await LoadSites();
    }

    private async Task LoadSites()
    {
        _sites = await InspectionSvc.GetSitesAsync();
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newName)) return;
        var site = new ConstructionSite { Name = _newName.Trim(), Address = _newAddress.Trim() };
        await InspectionSvc.SaveSiteAsync(site);
        _newName = "";
        _newAddress = "";
        await LoadSites();
    }

    private async Task DeleteSite(string id)
    {
        await InspectionSvc.DeleteSiteAsync(id);
        await LoadSites();
    }
}

