            <div class="photo-grid">
                @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
                {
                    <div class="photo-card">
                        <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.Caption" class="photo-thumbnail" />
                        <div class="photo-details">
                            <input type="text" class="form-input" placeholder="Add caption..."
                                   value="@photo.Caption"
                                   @onchange="(e) => UpdateCaption(photo, e.Value?.ToString() ?? "")" />
                            <button class="btn btn-danger btn-sm" @onclick="() => RemovePhoto(photo)">Remove</button>
                        </div>
                    </div>
                }
            </div>
