@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? _inspection;

    protected override async Task OnInitializedAsync()
    {
        await InspectionSvc.EnsureInitializedAsync();
        _inspection = await InspectionSvc.GetInspectionAsync(InspectionId);
    }

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        if (_inspection is null) return;

        var file = e.File;
        // Limit to 5MB
        var maxSize = 5 * 1024 * 1024;
        using var stream = file.OpenReadStream(maxSize);
        using var ms = new MemoryStream();
        await stream.CopyToAsync(ms);
        var base64 = Convert.ToBase64String(ms.ToArray());

        var photo = new InspectionPhoto
        {
            FileName = file.Name,
            Base64Data = base64
        };

        _inspection.Photos.Add(photo);
        await InspectionSvc.SaveInspectionAsync(_inspection);
    }

    private async Task UpdateCaption(InspectionPhoto photo, string caption)
    {
        photo.Caption = caption;
        await InspectionSvc.SaveInspectionAsync(_inspection!);
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        _inspection!.Photos.Remove(photo);
        await InspectionSvc.SaveInspectionAsync(_inspection);
    }
}

