        if (_inspection is null) return;

        var file = e.File;
        // Limit to 5MB
        var maxSize = 5 * 1024 * 1024;
        using var stream = file.OpenReadStream(maxSize);
        using var ms = new MemoryStream();
        await stream.CopyToAsync(ms);
        var base64 = Convert.ToBase64String(ms.ToArray());

        var photo = new InspectionPhoto
        {
            FileName = file.Name,
            Base64Data = base64
        };

        _inspection.Photos.Add(photo);
        await InspectionSvc.SaveInspectionAsync(_inspection);
    }

    private async Task UpdateCaption(InspectionPhoto photo, string caption)
    {
        photo.Caption = caption;
        await InspectionSvc.SaveInspectionAsync(_inspection!);
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        _inspection!.Photos.Remove(photo);
        await InspectionSvc.SaveInspectionAsync(_inspection);
    }
}

@page "/inspection/{InspectionId}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject InspectionService InspectionSvc
@inject NavigationManager Nav

<PageTitle>Inspection Detail - Site Inspector</PageTitle>

<div class="page-container">
    <header class="page-header">
        <a href="/" class="back-btn">← Home</a>
        <h1>Inspection</h1>
    </header>

    @if (_inspection is null)
    {
        <div class="loading">Loading...</div>
    }
    else
    {
        <div class="detail-card">
            <div class="detail-header">
                <h2>@_inspection.SiteName</h2>
                <span class="status-badge @_inspection.Status.ToString().ToLower()">@_inspection.Status</span>
            </div>
            <div class="detail-meta">
                <p><strong>Inspector:</strong> @_inspection.InspectorName</p>
                <p><strong>Date:</strong> @_inspection.InspectedAt.ToLocalTime().ToString("MMMM dd, yyyy HH:mm")</p>
                <p><strong>Sync:</strong> @(_inspection.IsSynced ? "✓ Synced" : "⏳ Pending")</p>
            </div>
        </div>

        <section class="summary-section">
            <h2>Checklist Summary</h2>
            <div class="summary-stats">
                <div class="stat pass">
                    <span class="stat-value">@_inspection.ChecklistItems.Count(i => i.Result == CheckResult.Pass)</span>
                    <span class="stat-label">Pass</span>
                </div>
                <div class="stat fail">
                    <span class="stat-value">@_inspection.ChecklistItems.Count(i => i.Result == CheckResult.Fail)</span>
                    <span class="stat-label">Fail</span>
                </div>
                <div class="stat na">
                    <span class="stat-value">@_inspection.ChecklistItems.Count(i => i.Result == CheckResult.NotApplicable)</span>
                    <span class="stat-label">N/A</span>
                </div>
                <div class="stat unchecked">
                    <span class="stat-value">@_inspection.ChecklistItems.Count(i => i.Result == CheckResult.NotChecked)</span>
                    <span class="stat-label">Pending</span>
                </div>
            </div>

            @{ var failures = _inspection.ChecklistItems.Where(i => i.Result == CheckResult.Fail).ToList(); }
            @if (failures.Any())
            {
                <div class="failures-list">
                    <h3>⚠️ Failed Items</h3>
                    @foreach (var item in failures)
                    {
                        <div class="failure-item">
                            <span>@item.Category: @item.Description</span>
                            @if (!string.IsNullOrEmpty(item.Notes))
                            {
                                <span class="failure-note">— @item.Notes</span>
                            }
                        </div>
                    }
                </div>
            }
        </section>

        <section class="notes-section">
            <h2>Notes</h2>
            <textarea class="form-input" rows="4" placeholder="Additional notes..."
                      value="@_inspection.Notes"
                      @onchange="UpdateNotes"></textarea>
        </section>

        @if (_inspection.Photos.Count > 0)
        {
            <section class="photos-section">
                <h2>Photos (@_inspection.Photos.Count)</h2>
                <div class="photo-grid-small">
                    @foreach (var photo in _inspection.Photos)
                    {
                        <div class="photo-thumb">
                            <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.Caption" />
                            @if (!string.IsNullOrEmpty(photo.Caption))
                            {
                                <span class="caption">@photo.Caption</span>
                            }
                        </div>
                    }
                </div>
            </section>
        }

        <div class="detail-actions">
            <a href="/inspection/@InspectionId/checklist" class="btn btn-secondary">📋 Edit Checklist</a>
            <a href="/inspection/@InspectionId/photos" class="btn btn-secondary">📷 Photos</a>
            @if (_inspection.Status == InspectionStatus.InProgress)
            {
                <button class="btn btn-primary btn-lg" @onclick="CompleteInspection">✓ Complete Inspection</button>
            }
            else
            {
                <div class="completed-badge">✓ Inspection Completed</div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? _inspection;

    protected override async Task OnInitializedAsync()
    {
        await InspectionSvc.EnsureInitializedAsync();
        _inspection = await InspectionSvc.GetInspectionAsync(InspectionId);
    }

    private async Task UpdateNotes(ChangeEventArgs e)
    {
        if (_inspection is null) return;
        _inspection.Notes = e.Value?.ToString() ?? "";
        await InspectionSvc.SaveInspectionAsync(_inspection);
    }

    private async Task CompleteInspection()
    {
        if (_inspection is null) return;
        _inspection.Status = InspectionStatus.Completed;
        await InspectionSvc.SaveInspectionAsync(_inspection);
    }
}

