arguments.new_str:
:root {
    --primary-color: #1565c0;
    --primary-dark: #0d47a1;
    --success-color: #2e7d32;
    --danger-color: #c62828;
    --warning-color: #f57f17;
    --neutral-color: #757575;
    --bg-color: #f5f5f5;
    --card-bg: #ffffff;
    --text-primary: #212121;
    --text-secondary: #616161;
    --border-color: #e0e0e0;
    --radius: 12px;
    --shadow: 0 2px 8px rgba(0,0,0,0.08);
}

*, *::before, *::after {
    box-sizing: border-box;
}

html, body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    margin: 0;
    padding: 0;
    background: var(--bg-color);
    color: var(--text-primary);
    -webkit-tap-highlight-color: transparent;
    font-size: 16px;
    line-height: 1.5;
}

/* Page containers */
.page-container, .dashboard {
    padding: 1rem;
    max-width: 600px;
    margin: 0 auto;
}

.page-header {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1.5rem;
    padding: 0.5rem 0;
}

.page-header h1 {
    font-size: 1.25rem;
    margin: 0;
}

.back-btn {
    color: var(--primary-color);
    text-decoration: none;
    font-weight: 500;
    min-height: 48px;
    display: flex;
    align-items: center;
}

/* Dashboard */
.dashboard-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1.5rem;
    padding: 0.5rem 0;
}

.dashboard-header h1 {
    font-size: 1.4rem;
    margin: 0;
}

.connectivity-badge {
    font-size: 0.8rem;
    font-weight: 600;
    padding: 4px 10px;
    border-radius: 20px;
}

.connectivity-badge.online {
    background: #e8f5e9;
    color: var(--success-color);
}

.connectivity-badge.offline {
    background: #fbe9e7;
    color: var(--danger-color);
}

/* Action cards */
.quick-actions {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
    margin-bottom: 2rem;
}

.action-card {
    background: var(--card-bg);
    border-radius: var(--radius);
    padding: 1.25rem 1rem;
    text-align: center;
    text-decoration: none;
    color: var(--text-primary);
    box-shadow: var(--shadow);
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 100px;
    transition: transform 0.1s;
}

.action-card:active {
    transform: scale(0.97);
}

.action-card.primary {
    background: var(--primary-color);
    color: white;
}

.action-icon {
