You are working on a Blazor Web App project at /tmp/sv-c2581b9b0c1c47c1aab9819820c47f5a/SiteInspector/

The project structure is:
- `SiteInspector/` - Server project (hosts the app, API endpoints)
- `SiteInspector.Client/` - Client WebAssembly project (all interactive UI)
- Global Interactive WebAssembly mode (all pages are interactive by default)
- .NET 11 preview, uses `net11.0` TFM

The app is for **building inspectors on construction sites**. Requirements:
- Inspectors fill out safety checklists and add notes at each site visit
- Photos attached to inspection reports
- **Offline-first**: must work without connectivity (construction sites have poor/no signal)
- Syncs data to server when connectivity returns
- Mobile-first (phones/tablets)
- Low-latency UI (inspectors tap through items quickly)
- No authentication

## Implementation Plan

### 1. Remove template pages
Delete `Counter.razor`, `Weather.razor` from `SiteInspector.Client/Pages/`. Keep `Home.razor` but rewrite it. Keep `NotFound.razor`.

### 2. Models (`SiteInspector.Client/Models/`)
Create shared models:
```csharp
// InspectionModels.cs
namespace SiteInspector.Client.Models;

public class ConstructionSite
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
}

public class Inspection
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string SiteId { get; set; } = "";
    public string SiteName { get; set; } = "";
    public string InspectorName { get; set; } = "";
    public DateTime InspectedAt { get; set; } = DateTime.UtcNow;
    public string Notes { get; set; } = "";
    public List<ChecklistItem> ChecklistItems { get; set; } = new();
    public List<InspectionPhoto> Photos { get; set; } = new();
    public bool IsSynced { get; set; } = false;
    public InspectionStatus Status { get; set; } = InspectionStatus.InProgress;
}

public enum InspectionStatus { InProgress, Completed }

public class ChecklistItem
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Category { get; set; } = "";
    public string Description { get; set; } = "";
    public CheckResult Result { get; set; } = CheckResult.NotChecked;
    public string Notes { get; set; } = "";
}

public enum CheckResult { NotChecked, Pass, Fail, NotApplicable }

public class InspectionPhoto
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string FileName { get; set; } = "";
    public string Base64Data { get; set; } = "";  // stored as base64 for IndexedDB
    public string Caption { get; set; } = "";
    public DateTime TakenAt { get; set; } = DateTime.UtcNow;
}
```

### 3. IndexedDB JavaScript module (`SiteInspector.Client/wwwroot/js/indexedDb.js`)
Create a JS module that provides IndexedDB CRUD operations:
- `initDb()` - creates/opens the database with object stores: `sites`, `inspections`
- `putItem(storeName, item)` - add or update
- `getItem(storeName, id)` - get by id
- `getAllItems(storeName)` - get all from store
- `deleteItem(storeName, id)` - delete by id
- `getItemsByIndex(storeName, indexName, value)` - query by index (e.g., inspections by siteId)

Database name: `SiteInspectorDb`, version 1.
Object stores:
- `sites` with keyPath `id`
- `inspections` with keyPath `id`, index on `siteId` and `isSynced`

### 4. Services (`SiteInspector.Client/Services/`)

**ILocalStore.cs** - interface for local persistence:
```csharp
namespace SiteInspector.Client.Services;

public interface ILocalStore
{
    Task InitializeAsync();
    Task<List<T>> GetAllAsync<T>(string storeName);
    Task<T?> GetAsync<T>(string storeName, string id);
    Task PutAsync<T>(string storeName, T item);
    Task DeleteAsync(string storeName, string id);
    Task<List<T>> GetByIndexAsync<T>(string storeName, string indexName, string value);
}
```

**IndexedDbStore.cs** - implementation using IJSRuntime to call the JS module:
```csharp
using Microsoft.JSInterop;
using System.Text.Json;

namespace SiteInspector.Client.Services;

public class IndexedDbStore : ILocalStore, IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public IndexedDbStore(IJSRuntime js) => _js = js;

    public async Task InitializeAsync()
    {
        _module = await _js.InvokeAsync<IJSObjectReference>("import", "./js/indexedDb.js");
        await _module.InvokeVoidAsync("initDb");
    }

    public async Task<List<T>> GetAllAsync<T>(string storeName)
    {
        EnsureInitialized();
        var json = await _module!.InvokeAsync<string>("getAllItems", storeName);
        return JsonSerializer.Deserialize<List<T>>(json, JsonOpts) ?? new();
    }

    public async Task<T?> GetAsync<T>(string storeName, string id)
    {
        EnsureInitialized();
        var json = await _module!.InvokeAsync<string?>("getItem", storeName, id);
        return json is null ? default : JsonSerializer.Deserialize<T>(json, JsonOpts);
    }

    public async Task PutAsync<T>(string storeName, T item)
    {
        EnsureInitialized();
        var json = JsonSerializer.Serialize(item, JsonOpts);
        await _module!.InvokeVoidAsync("putItem", storeName, json);
    }

    public async Task DeleteAsync(string storeName, string id)
    {
        EnsureInitialized();
        await _module!.InvokeVoidAsync("deleteItem", storeName, id);
    }

    public async Task<List<T>> GetByIndexAsync<T>(string storeName, string indexName, string value)
    {
        EnsureInitialized();
        var json = await _module!.InvokeAsync<string>("getItemsByIndex", storeName, indexName, value);
        return JsonSerializer.Deserialize<List<T>>(json, JsonOpts) ?? new();
    }

    private void EnsureInitialized()
    {
        if (_module is null) throw new InvalidOperationException("Store not initialized. Call InitializeAsync first.");
    }

    private static JsonSerializerOptions JsonOpts => new() { PropertyNamingPolicy = JsonNamingPolicy.CamelCase };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null) await _module.DisposeAsync();
    }
}
```

**InspectionService.cs** - high-level operations combining store + business logic:
```csharp
namespace SiteInspector.Client.Services;

using SiteInspector.Client.Models;

public class InspectionService
{
    private readonly ILocalStore _store;
    private bool _initialized;

    public InspectionService(ILocalStore store) => _store = store;

    public async Task EnsureInitializedAsync()
    {
        if (!_initialized)
        {
            await _store.InitializeAsync();
            _initialized = true;
        }
    }

    // Sites
    public Task<List<ConstructionSite>> GetSitesAsync() => _store.GetAllAsync<ConstructionSite>("sites");
    public Task<ConstructionSite?> GetSiteAsync(string id) => _store.GetAsync<ConstructionSite>("sites", id);
    public Task SaveSiteAsync(ConstructionSite site) => _store.PutAsync("sites", site);
    public Task DeleteSiteAsync(string id) => _store.DeleteAsync("sites", id);

    // Inspections
    public Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId) => _store.GetByIndexAsync<Inspection>("inspections", "siteId", siteId);
    public Task<List<Inspection>> GetAllInspectionsAsync() => _store.GetAllAsync<Inspection>("inspections");
    public Task<Inspection?> GetInspectionAsync(string id) => _store.GetAsync<Inspection>("inspections", id);
    public Task SaveInspectionAsync(Inspection inspection) => _store.PutAsync("inspections", inspection);
