1. const DB_NAME = 'SiteInspectorDb';
2. const DB_VERSION = 1;
3. 
4. let db = null;
5. 
6. export function initDb() {
7.     return new Promise((resolve, reject) => {
8.         if (db) { resolve(); return; }
9.         const request = indexedDB.open(DB_NAME, DB_VERSION);
10.         request.onupgradeneeded = (event) => {
11.             const database = event.target.result;
12.             if (!database.objectStoreNames.contains('sites')) {
13.                 database.createObjectStore('sites', { keyPath: 'id' });
14.             }
15.             if (!database.objectStoreNames.contains('inspections')) {
16.                 const store = database.createObjectStore('inspections', { keyPath: 'id' });
17.                 store.createIndex('siteId', 'siteId', { unique: false });
18.                 store.createIndex('isSynced', 'isSynced', { unique: false });
19.             }
20.         };
21.         request.onsuccess = (event) => {
22.             db = event.target.result;
23.             resolve();
24.         };
25.         request.onerror = (event) => reject(event.target.error);
26.     });
27. }
28. 
29. export function putItem(storeName, jsonString) {
30.     return new Promise((resolve, reject) => {
31.         const item = JSON.parse(jsonString);
32.         const tx = db.transaction(storeName, 'readwrite');
33.         const store = tx.objectStore(storeName);
34.         const request = store.put(item);
35.         request.onsuccess = () => resolve();
36.         request.onerror = (event) => reject(event.target.error);
37.     });
38. }
39. 
40. export function getItem(storeName, id) {
41.     return new Promise((resolve, reject) => {
42.         const tx = db.transaction(storeName, 'readonly');
43.         const store = tx.objectStore(storeName);
44.         const request = store.get(id);
45.         request.onsuccess = () => {
46.             resolve(request.result ? JSON.stringify(request.result) : null);
47.         };
48.         request.onerror = (event) => reject(event.target.error);
49.     });
50. }
51. 
52. export function getAllItems(storeName) {
53.     return new Promise((resolve, reject) => {
54.         const tx = db.transaction(storeName, 'readonly');
55.         const store = tx.objectStore(storeName);
56.         const request = store.getAll();
57.         request.onsuccess = () => resolve(JSON.stringify(request.result || []));
58.         request.onerror = (event) => reject(event.target.error);
59.     });
60. }
61. 
62. export function deleteItem(storeName, id) {
63.     return new Promise((resolve, reject) => {
64.         const tx = db.transaction(storeName, 'readwrite');
65.         const store = tx.objectStore(storeName);
66.         const request = store.delete(id);
67.         request.onsuccess = () => resolve();
68.         request.onerror = (event) => reject(event.target.error);
69.     });
70. }
71. 
72. export function getItemsByIndex(storeName, indexName, value) {
73.     return new Promise((resolve, reject) => {
74.         const tx = db.transaction(storeName, 'readonly');
75.         const store = tx.objectStore(storeName);
76.         const index = store.index(indexName);
77.         // Convert string 'false'/'true' to boolean for isSynced index
78.         let queryValue = value;
79.         if (value === 'true') queryValue = true;
80.         else if (value === 'false') queryValue = false;
81.         const request = index.getAll(queryValue);
82.         request.onsuccess = () => resolve(JSON.stringify(request.result || []));
83.         request.onerror = (event) => reject(event.target.error);
84.     });
85. }
86.

